create extension if not exists pgcrypto;
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, email text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.companies (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, website text, industry text, location text, status text default 'active' check (status in ('active','inactive')), created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.jd_templates (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, company_id uuid not null references public.companies(id) on delete cascade, job_title text not null, department text, location text, work_mode text, job_type text, min_experience_years numeric, max_experience_years numeric, required_skills text[] default '{}', nice_to_have_skills text[] default '{}', responsibilities text, qualifications text, jd_text text, shortlist_score integer default 70 check (shortlist_score between 0 and 100), status text default 'draft' check (status in ('draft','active','archived')), current_version integer default 1, current_jd_hash text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.jd_versions (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, jd_template_id uuid not null references public.jd_templates(id) on delete cascade, company_id uuid not null references public.companies(id) on delete cascade, version_number integer not null, jd_snapshot_json jsonb not null, jd_hash text not null, change_note text, created_at timestamptz default now(), unique(jd_template_id,version_number));
alter table public.profiles enable row level security; alter table public.companies enable row level security; alter table public.jd_templates enable row level security; alter table public.jd_versions enable row level security;
create policy "profiles_owner_all" on public.profiles for all using (id=auth.uid()) with check (id=auth.uid());
create policy "companies_owner_all" on public.companies for all using (user_id=auth.uid()) with check (user_id=auth.uid());
create policy "jds_owner_all" on public.jd_templates for all using (user_id=auth.uid()) with check (user_id=auth.uid());
create policy "versions_owner_all" on public.jd_versions for all using (user_id=auth.uid()) with check (user_id=auth.uid());
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,full_name,email) values(new.id,coalesce(new.raw_user_meta_data->>'full_name','HR Manager'),new.email); return new; end; $$;
drop trigger if exists on_auth_user_created on auth.users; create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
create index if not exists companies_user_id_idx on public.companies(user_id); create index if not exists jds_user_id_idx on public.jd_templates(user_id); create index if not exists jds_company_id_idx on public.jd_templates(company_id); create index if not exists versions_jd_idx on public.jd_versions(jd_template_id,version_number desc);
